    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        // {
        //     "direction": "Short",
        //     "entryNotional": "10.302213",
        //     "notionalValue": "10.225008",
        //     "quantity": "0.004310550",
        //     "symbol": "ETH/USDT-P",
        //     "unrealizedFundingPnl": "0.000000",
        //     "unrealizedTradingPnl": "0.077204"
        // }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(position, "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object side = this.safeStringLower(position, "direction");
        Object quantity = this.safeString(position, "quantity");
        Object unrealizedFunding = this.safeString(position, "unrealizedFundingPnl", "0");
        Object unrealizedTrading = this.safeString(position, "unrealizedTradingPnl", "0");
        Object unrealizedPnl = Precise.stringAdd(unrealizedFunding, unrealizedTrading);
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", null );
            put( "symbol", symbol );
            put( "entryPrice", HibachiCore.this.safeString(position, "average_entry_price") );
            put( "markPrice", null );
            put( "notional", HibachiCore.this.safeString(position, "notionalValue") );
            put( "collateral", null );
            put( "unrealizedPnl", unrealizedPnl );
            put( "side", side );
            put( "contracts", HibachiCore.this.parseNumber(quantity) );
            put( "contractSize", null );
            put( "timestamp", null );
            put( "datetime", null );
            put( "hedged", null );
            put( "maintenanceMargin", null );
            put( "maintenanceMarginPercentage", null );
            put( "initialMargin", null );
            put( "initialMarginPercentage", null );
            put( "leverage", null );
            put( "liquidationPrice", null );
            put( "marginRatio", null );
            put( "marginMode", null );
            put( "percentage", null );
        }});
    }

    public Object sign(Object path, Object... optionalArgs)
    {
        Object api = Helpers.getArg(optionalArgs, 0, "public");
        Object method = Helpers.getArg(optionalArgs, 1, "GET");
        Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
        Object headers = Helpers.getArg(optionalArgs, 3, null);
        Object body = Helpers.getArg(optionalArgs, 4, null);
        Object endpoint = Helpers.add("/", this.implodeParams(path, parameters));
        Object url = Helpers.add(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), api), endpoint);
        headers = new java.util.HashMap<String, Object>() {{
            put( "Hibachi-Client", "HibachiCCXT/unversioned" );
        }};
        if (Helpers.isTrue(Helpers.isEqual(method, "GET")))
        {
            Object request = this.omit(parameters, this.extractParams(path));
            Object query = this.urlencode(request);
            if (Helpers.isTrue(!Helpers.isEqual(Helpers.getArrayLength(query), 0)))
            {
                url = Helpers.add(url, Helpers.add("?", query));
            }
        }
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(method, "POST")) || Helpers.isTrue(Helpers.isEqual(method, "PUT"))) || Helpers.isTrue(Helpers.isEqual(method, "DELETE"))))
        {
            Helpers.addElementToObject(headers, "Content-Type", "application/json");
            body = this.json(parameters);
        }
        if (Helpers.isTrue(Helpers.isEqual(api, "private")))
        {
            this.checkRequiredCredentials();
            Helpers.addElementToObject(headers, "Authorization", this.apiKey);
        }
        final Object finalUrl = url;
        final Object finalMethod = method;
        final Object finalBody = body;
        final Object finalHeaders = headers;
        return new java.util.HashMap<String, Object>() {{
            put( "url", finalUrl );
            put( "method", finalMethod );
            put( "body", finalBody );
            put( "headers", finalHeaders );
        }};
    }

    public Object handleErrors(Object httpCode, Object reason, Object url, Object method, Object headers, Object body, Object response, Object requestHeaders, Object requestBody)
    {
        if (Helpers.isTrue(Helpers.isEqual(response, null)))
        {
            return null;  // fallback to default error handler
        }
        if (Helpers.isTrue(Helpers.inOp(response, "status")))
        {
            //
            //     {"errorCode":4,"message":"Invalid input: Invalid quantity: 0","status":"failed"}
            //
            Object status = this.safeString(response, "status");
            if (Helpers.isTrue(Helpers.isEqual(status, "failed")))
            {
                Object code = this.safeString(response, "errorCode");
                Object feedback = Helpers.add(Helpers.add(this.id, " "), body);
                this.throwBroadlyMatchedException(Helpers.GetValue(this.exceptions, "broad"), body, feedback);
                this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), code, feedback);
                Object message = this.safeString(response, "message");
                this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), message, feedback);
                throw new ExchangeError((String)feedback) ;
            }
        }
        return null;
    }

    public Object parseTransactionType(Object type)
    {
        Object types = new java.util.HashMap<String, Object>() {{
            put( "deposit", "transaction" );
            put( "withdrawal", "transaction" );
            put( "transfer-in", "transfer" );
            put( "transfer-out", "transfer" );
        }};
        return this.safeString(types, type, type);
    }

    public Object parseTransactionStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "pending", "pending" );
            put( "claimable", "pending" );
            put( "completed", "ok" );
            put( "failed", "canceled" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object transactionType = this.safeString(item, "transactionType");
        Object timestamp = null;
        Object type = null;
        Object direction = null;
        Object amount = null;
        Object fee = null;
        Object referenceId = null;
        Object referenceAccount = null;
        Object status = null;
        if (Helpers.isTrue(Helpers.isEqual(transactionType, null)))
        {
            // response from TradeAccountTradingHistory
            timestamp = this.safeIntegerProduct(item, "timestamp", 1000);
            type = "trade";
            Object amountStr = this.safeString(item, "realizedPnl");
            if (Helpers.isTrue(Precise.stringLt(amountStr, "0")))
            {
                direction = "out";
                amountStr = Precise.stringNeg(amountStr);
            } else
            {
                direction = "in";
            }
            amount = this.parseNumber(amountStr);
            fee = new java.util.HashMap<String, Object>() {{
                put( "currency", "USDT" );
                put( "cost", HibachiCore.this.safeNumber(item, "fee") );
            }};
            status = "ok";
        } else
        {
            // response from CapitalHistory
            timestamp = this.safeIntegerProduct(item, "timestampSec", 1000);
            amount = this.safeNumber(item, "quantity");
            direction = ((Helpers.isTrue((Helpers.isTrue(Helpers.isEqual(transactionType, "deposit")) || Helpers.isTrue(Helpers.isEqual(transactionType, "transfer-in")))))) ? "in" : "out";
            type = this.parseTransactionType(transactionType);
            status = this.parseTransactionStatus(this.safeString(item, "status"));
            if (Helpers.isTrue(Helpers.isEqual(transactionType, "transfer-in")))
            {
                referenceAccount = this.safeString(item, "srcAccountId");
            } else if (Helpers.isTrue(Helpers.isEqual(transactionType, "transfer-out")))
            {
                referenceAccount = this.safeString(item, "receivingAccountId");
            }
            referenceId = this.safeString(item, "transactionHash");
        }
        final Object finalReferenceAccount = referenceAccount;
        final Object finalReferenceId = referenceId;
        final Object finalStatus = status;
        final Object finalAmount = amount;
        final Object finalFee = fee;
        final Object finalDirection = direction;
        final Object finalTimestamp = timestamp;
        final Object finalType = type;
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "id", HibachiCore.this.safeString(item, "id") );
            put( "currency", HibachiCore.this.currency("USDT") );
            put( "account", HibachiCore.this.numberToString(HibachiCore.this.accountId) );
            put( "referenceAccount", finalReferenceAccount );
            put( "referenceId", finalReferenceId );
            put( "status", finalStatus );
            put( "amount", finalAmount );
            put( "before", null );
            put( "after", null );
            put( "fee", finalFee );
            put( "direction", finalDirection );
            put( "timestamp", finalTimestamp );
            put( "datetime", HibachiCore.this.iso8601(finalTimestamp) );
            put( "type", finalType );
            put( "info", item );
        }}, currency);
    }

