    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeIntegerProduct(transaction, "timestampSec", 1000);
        Object address = this.safeString(transaction, "withdrawalAddress");
        Object transactionType = this.safeString(transaction, "transactionType");
        if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(transactionType, "deposit")) && Helpers.isTrue(!Helpers.isEqual(transactionType, "withdrawal"))))
        {
            transactionType = this.parseTransactionType(transactionType);
        }
        final Object finalTransactionType = transactionType;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", HibachiCore.this.safeString(transaction, "id") );
            put( "txid", HibachiCore.this.safeString(transaction, "transactionHash") );
            put( "timestamp", timestamp );
            put( "datetime", HibachiCore.this.iso8601(timestamp) );
            put( "network", "ARBITRUM" );
            put( "address", address );
            put( "addressTo", address );
            put( "addressFrom", null );
            put( "tag", null );
            put( "tagTo", null );
            put( "tagFrom", null );
            put( "type", finalTransactionType );
            put( "amount", HibachiCore.this.safeNumber(transaction, "quantity") );
            put( "currency", "USDT" );
            put( "status", HibachiCore.this.parseTransactionStatus(HibachiCore.this.safeString(transaction, "status")) );
            put( "updated", null );
            put( "internal", null );
            put( "comment", null );
            put( "fee", null );
        }};
    }

